import React, { useCallback, useMemo, useState } from "react";
import { ExternalLink } from "lucide-react";
import { Link } from "react-router-dom";

import Avatar from "@/components/primitives/Avatar";
import { useToastStore } from "@/state/toastStore";
import { useWalletStore } from "@/state/walletStore";
import { getCreditTier } from "@/types/contract";
import { stellarExpertAccountUrl, truncateAddress } from "@/utils/format";
import type { Profile } from "@/types/contract";

function displayInitials(displayName: string): string {
  const parts = displayName.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "?";
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return `${parts[0][0] ?? ""}${parts[parts.length - 1][0] ?? ""}`.toUpperCase();
}

export interface DashboardHomeCreatorCardProps {
  profile: Profile;
  zapLink: string;
}

/**
 * Ko-fi–style profile summary: avatar, identity, metric row, soft CTAs.
 */
const DashboardHomeCreatorCard: React.FC<DashboardHomeCreatorCardProps> = ({
  profile,
  zapLink,
}) => {
  const network = useWalletStore((s) => s.network);
  const { addToast } = useToastStore();
  const [addrCopied, setAddrCopied] = useState(false);

  const explorerAccount = stellarExpertAccountUrl(profile.owner, network);
  const tier = getCreditTier(profile.creditScore);

  const copyAddress = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(profile.owner);
      setAddrCopied(true);
      window.setTimeout(() => setAddrCopied(false), 2000);
    } catch {
      addToast({ message: "Couldn’t copy address.", type: "error", duration: 2500 });
    }
  }, [addToast, profile.owner]);

  const copyLink = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(zapLink);
      addToast({
        message: "Link copied — paste it anywhere your fans are.",
        type: "success",
        duration: 3000,
      });
    } catch {
      addToast({ message: "Couldn’t copy link.", type: "error", duration: 2500 });
    }
  }, [addToast, zapLink]);

  const shareOnX = useCallback(() => {
    const text = encodeURIComponent(`Support me on Zap402 — ${zapLink}`);
    window.open(
      `https://twitter.com/intent/tweet?text=${text}`,
      "_blank",
      "noopener,noreferrer",
    );
  }, [zapLink]);

  const publicPath = `/@${profile.username}`;

  const followersLabel = useMemo(
    () =>
      profile.xHandle?.trim()
        ? profile.xFollowers.toLocaleString()
        : "—",
    [profile.xFollowers, profile.xHandle],
  );

  return (
    <div className="kofi-dashboard-card overflow-hidden shadow-none">
      <div className="flex flex-col gap-5 p-6 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex min-w-0 flex-1 items-start gap-4">
          <Avatar
            src={profile.imageUrl}
            alt={profile.displayName}
            size="lg"
            address={profile.owner}
            fallback={displayInitials(profile.displayName)}
            className="!h-[72px] !w-[72px] shrink-0 rounded-full border border-[var(--card-border-soft)] text-[22px]"
          />
          <div className="min-w-0 flex-1">
            <h2 className="font-body text-2xl font-semibold leading-tight tracking-tight text-zap-ink">
              {profile.displayName}
            </h2>
            <p className="mt-0.5 font-body text-sm text-zap-ink-muted">@{profile.username}</p>
            <div className="mt-3 flex flex-wrap items-center gap-2">
              <span className="inline-flex max-w-full items-center rounded-full border border-[var(--card-border-soft)] bg-zap-bg-alt px-2.5 py-1 font-mono text-[11px] text-zap-ink-muted">
                {truncateAddress(profile.owner, 4)}
              </span>
              <button
                type="button"
                onClick={() => void copyAddress()}
                className="font-body text-xs font-medium text-zap-teal underline decoration-zap-border underline-offset-2"
              >
                {addrCopied ? "Copied" : "Copy"}
              </button>
              <a
                href={explorerAccount}
                target="_blank"
                rel="noopener noreferrer"
                className="inline-flex items-center gap-0.5 font-body text-xs font-medium text-zap-ink-muted no-underline hover:text-zap-teal"
              >
                View
                <ExternalLink className="h-3 w-3 shrink-0 opacity-70" aria-hidden />
              </a>
            </div>
          </div>
        </div>
        <Link
          to="/profile/edit"
          className="inline-flex shrink-0 items-center font-body justify-center self-start rounded-full border border-zap-border bg-zap-bg-alt px-4 py-2 font-body text-sm font-semibold text-zap-ink no-underline transition-colors hover:border-zap-border-bright hover:bg-zap-bg-overlay"
        >
          Edit profile
        </Link>
      </div>

      {profile.bio?.trim() ? (
        <p className="border-t border-[var(--card-border-soft)] px-6 pb-5 pt-4 font-body text-sm leading-relaxed text-zap-ink-muted">
          {profile.bio.trim()}
        </p>
      ) : null}

      <div className="grid grid-cols-3 divide-x divide-[var(--card-border-soft)] border-t border-[var(--card-border-soft)] bg-zap-bg-alt/50">
        <div className="px-4 py-4 text-center sm:px-6">
          <p className="font-body text-xs text-zap-ink-muted">Zaps</p>
          <p className="mt-1 font-body text-2xl font-semibold tabular-nums text-zap-ink">
            {profile.totalTipsCount.toLocaleString()}
          </p>
        </div>
        <div className="px-4 py-4 text-center sm:px-6">
          <p className="font-body text-xs text-zap-ink-muted">Credit</p>
          <p className="mt-1 font-body text-2xl font-semibold tabular-nums text-zap-ink">
            {profile.creditScore}
          </p>
          <p className="mt-0.5 font-body text-[11px] capitalize text-zap-ink-faint">{tier}</p>
        </div>
        <div className="px-4 py-4 text-center sm:px-6">
          <p className="font-body text-xs text-zap-ink-muted">Followers</p>
          <p className="mt-1 font-body text-2xl font-semibold tabular-nums text-zap-ink">
            {followersLabel}
          </p>
          <p className="mt-0.5 font-body text-[11px] text-zap-ink-faint">X</p>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-2 border-t border-[var(--card-border-soft)] p-4 sm:grid-cols-3">
        <button
          type="button"
          onClick={() => void copyLink()}
          className="inline-flex min-h-[44px] items-center justify-center rounded-full border border-zap-border bg-zap-bg-raised px-3 py-2.5 font-body text-sm font-semibold text-zap-ink transition-colors hover:border-zap-border-bright hover:bg-zap-bg-alt"
        >
          Copy link
        </button>
        <button
          type="button"
          onClick={shareOnX}
          className="inline-flex min-h-[44px] items-center justify-center rounded-full border border-zap-border bg-zap-bg-raised px-3 py-2.5 font-body text-sm font-semibold text-zap-ink transition-colors hover:border-zap-border-bright hover:bg-zap-bg-alt"
        >
          Share on X
        </button>
        <Link
          to={publicPath}
          target="_blank"
          rel="noopener noreferrer"
          className="inline-flex min-h-[44px] items-center justify-center gap-1 rounded-full border border-zap-border bg-zap-bg-raised px-3 py-2.5 font-body text-sm font-semibold text-zap-ink no-underline transition-colors hover:border-zap-border-bright hover:bg-zap-bg-alt"
        >
          My page
          <span aria-hidden>↗</span>
        </Link>
      </div>
    </div>
  );
};

export default DashboardHomeCreatorCard;
