import React from "react";
import { useNavigate } from "react-router-dom";

import DashboardHomeCreatorCard from "@/sections/dashboard/DashboardHomeCreatorCard";
import GettingStartedCard from "@/sections/dashboard/GettingStartedCard";
import HomeGuidesSection from "@/sections/dashboard/HomeGuidesSection";
import TerminalHeroSummary from "@/sections/dashboard/TerminalHeroSummary";
import ActivityMini from "@/sections/dashboard/ActivityMini";
import TerminalSetupSuggestions from "@/sections/dashboard/TerminalSetupSuggestions";
import type { Profile, Tip } from "@/types/contract";

export interface DashboardHomePanelProps {
  profile: Profile;
  tips: Tip[];
  zapLink: string;
  onWithdraw?: () => void;
  feeBps?: number;
}

/**
 * Creator home — Ko-fi–inspired layout: onboarding, profile, earnings, activity, suggestions, guides.
 */
const DashboardHomePanel: React.FC<DashboardHomePanelProps> = ({
  profile,
  tips,
  zapLink,
  onWithdraw,
  feeBps,
}) => {
  const navigate = useNavigate();

  return (
    <div className="space-y-6">
      <GettingStartedCard profile={profile} tips={tips} zapLink={zapLink} />

      <DashboardHomeCreatorCard profile={profile} zapLink={zapLink} />

      <TerminalHeroSummary
        profile={profile}
        onWithdraw={onWithdraw}
        feeBps={feeBps}
      />

      <ActivityMini
        tips={tips}
        variant="home"
        onViewAll={() => navigate("/terminal/earnings")}
      />

      <TerminalSetupSuggestions zapLink={zapLink} />

      <HomeGuidesSection />
    </div>
  );
};

export default DashboardHomePanel;
