import React, { useCallback, useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import {
  AlertTriangle,
  Bell,
  Copy,
  Download,
  Pencil,
  Share2,
  Trash2,
  User,
} from "lucide-react";
import { QRCodeCanvas } from "qrcode.react";

import DashboardTabPageHeader from "@/components/dashboard/DashboardTabPageHeader";
import Button from "@/components/primitives/Button";
import { useDocumentTheme } from "@/hooks/useDocumentTheme";
import { DashboardSectionHeader } from "@/sections/dashboard/DashboardSectionHeader";
import { dashboardSectionIconLucideProps } from "@/sections/dashboard/DashboardSectionIcon";
import type { Profile } from "@/types";

const TIP_DOMAIN = import.meta.env.VITE_APP_URL || window.location.origin;

const QR_CANVAS_ID = "settings-tip-qr-canvas";

const tipUrlFieldClass =
  "flex min-h-10 w-full min-w-0 max-w-full flex-1 items-center overflow-hidden rounded-2xl border border-[var(--card-border-soft)] bg-zap-surface px-3 py-2 text-sm font-medium text-zap-ink shadow-none [overflow-wrap:anywhere] [word-break:break-word]";

const NOTIFY_STORAGE_KEY = "zap402.settings.notifications";

type NotifyPrefId = "tips" | "weekly" | "product";

type NotifyPrefs = Record<NotifyPrefId, boolean>;

const defaultNotifyPrefs: NotifyPrefs = {
  tips: false,
  weekly: false,
  product: false,
};

function readNotifyPrefs(): NotifyPrefs {
  if (typeof window === "undefined") return { ...defaultNotifyPrefs };
  try {
    const raw = localStorage.getItem(NOTIFY_STORAGE_KEY);
    if (!raw) return { ...defaultNotifyPrefs };
    const parsed = JSON.parse(raw) as Partial<NotifyPrefs>;
    return {
      tips: Boolean(parsed.tips),
      weekly: Boolean(parsed.weekly),
      product: Boolean(parsed.product),
    };
  } catch {
    return { ...defaultNotifyPrefs };
  }
}

function writeNotifyPrefs(prefs: NotifyPrefs) {
  if (typeof window === "undefined") return;
  try {
    localStorage.setItem(NOTIFY_STORAGE_KEY, JSON.stringify(prefs));
  } catch {
    /* ignore quota / private mode */
  }
}

interface SettingsTabProps {
  profile: Profile;
}

const settingsActionBtnClass = "w-full justify-center sm:w-auto";

/** One height for all Settings actions (overrides editorial SCSS min-height 48px on primary/ghost base). */
const settingsUniformH = "!min-h-10 !h-10 max-h-10 shrink-0";

const SettingsTab: React.FC<SettingsTabProps> = ({ profile }) => {
  const navigate = useNavigate();
  const tipUrl = `${TIP_DOMAIN}/@${profile.username}`;
  const [linkCopied, setLinkCopied] = useState(false);
  const [notifyPrefs, setNotifyPrefs] = useState<NotifyPrefs>(() => readNotifyPrefs());
  const theme = useDocumentTheme();

  useEffect(() => {
    if (typeof window === "undefined") return;
    if (window.location.hash === "#my-purchases") {
      navigate("/terminal/purchases", { replace: true });
    }
  }, [navigate]);

  const qrBg = theme === "light" ? "#ffffff" : "#0d1210";
  const qrFg = theme === "light" ? "#0a1a0c" : "#d4ddd4";

  const copyPublicLink = async () => {
    try {
      await navigator.clipboard.writeText(tipUrl);
      setLinkCopied(true);
      setTimeout(() => setLinkCopied(false), 2000);
    } catch {
      /* ignore */
    }
  };

  const shareOnX = () => {
    const text = encodeURIComponent("Send me tips on Zap402!");
    const url = encodeURIComponent(tipUrl);
    window.open(
      `https://twitter.com/intent/tweet?text=${text}&url=${url}`,
      "_blank",
      "width=550,height=420",
    );
  };

  const setNotifyPref = useCallback((id: NotifyPrefId, checked: boolean) => {
    setNotifyPrefs((prev) => {
      const next = { ...prev, [id]: checked };
      writeNotifyPrefs(next);
      return next;
    });
  }, []);

  const downloadQrPng = useCallback(() => {
    const canvas = document.getElementById(QR_CANVAS_ID) as HTMLCanvasElement | null;
    if (!canvas) return;
    const pngUrl = canvas
      .toDataURL("image/png")
      .replace("image/png", "image/octet-stream");
    const a = document.createElement("a");
    a.href = pngUrl;
    a.download = "zap402-tip-qr.png";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  }, []);

  return (
    <div className="space-y-6">
      <DashboardTabPageHeader
        kicker="06 / Settings"
        title="Settings"
        description="Sharing, notifications, and account options."
      />

      <div className="kofi-dashboard-card space-y-4 p-5 shadow-none md:p-6">
        <DashboardSectionHeader
          icon={<User {...dashboardSectionIconLucideProps} aria-hidden />}
          title="Profile"
        >
          <p className="max-w-xl text-pretty text-sm font-medium leading-relaxed text-zap-ink-muted">
            Username and display name shown on your public page.
          </p>
        </DashboardSectionHeader>
        <div className="space-y-3 rounded-2xl border border-[var(--card-border-soft)] bg-zap-bg/25 p-4 dark:bg-zap-bg/10">
          <div className="flex flex-wrap items-baseline justify-between gap-2 border-b border-[var(--card-border-soft)] pb-3">
            <span className="text-[10px] font-semibold uppercase tracking-[0.12em] text-zap-ink-muted">
              Username
            </span>
            <span className="font-body text-base font-semibold text-zap-ink">
              @{profile.username}
            </span>
          </div>
          <div className="flex flex-wrap items-baseline justify-between gap-2">
            <span className="text-[10px] font-semibold uppercase tracking-[0.12em] text-zap-ink-muted">
              Display name
            </span>
            <span className="font-body text-base font-semibold text-zap-ink">
              {profile.displayName || "—"}
            </span>
          </div>
        </div>
        <Link
          to="/profile/edit"
          className={`btn-editorial-ghost btn-editorial-ghost--compact font-body inline-flex w-full items-center justify-center gap-2 !font-medium no-underline normal-case tracking-normal sm:w-auto ${settingsUniformH}`}
        >
          <Pencil size={16} className="shrink-0 font-body opacity-90" aria-hidden />
          Edit profile
        </Link>
      </div>

      <div className="kofi-dashboard-card space-y-4 p-5 shadow-none md:p-6">
        <DashboardSectionHeader
          icon={<Share2 {...dashboardSectionIconLucideProps} aria-hidden />}
          title="Share"
        >
          <p className="text-pretty text-sm font-medium leading-relaxed text-zap-ink-muted">
            Copy your link anywhere, post to X, or use the QR — scan to open your tip page; download a
            PNG for posters or stories.
          </p>
        </DashboardSectionHeader>
        <div className="space-y-5">
          <div className="flex w-full min-w-0 flex-col gap-3 sm:flex-row sm:flex-wrap sm:items-stretch">
            <div className={`${tipUrlFieldClass} min-w-0 flex-1 font-mono text-[13px]`}>
              {tipUrl}
            </div>
            <div className="flex flex-col gap-2 sm:flex-row sm:items-stretch">
              <Button
                type="button"
                variant="editorialGhost"
                size="sm"
                className={`shrink-0 sm:self-start ${settingsActionBtnClass} ${settingsUniformH}`}
                icon={<Copy size={16} />}
                onClick={() => void copyPublicLink()}
              >
                {linkCopied ? "Copied!" : "Copy"}
              </Button>
              <Button
                type="button"
                variant="editorialGhost"
                size="sm"
                className={`shrink-0 sm:self-start ${settingsActionBtnClass} ${settingsUniformH}`}
                icon={<Share2 size={16} aria-hidden />}
                onClick={shareOnX}
              >
                Share on X
              </Button>
            </div>
          </div>
          <div className="flex flex-col gap-3 border-t border-[var(--card-border-soft)] pt-5">
            <p className="text-[10px] font-semibold uppercase tracking-[0.12em] text-zap-ink-muted">
              QR code
            </p>
            <div className="inline-flex w-fit border border-[var(--card-border-soft)] bg-zap-surface p-3 shadow-none dark:bg-zap-bg-raised">
              <QRCodeCanvas
                id={QR_CANVAS_ID}
                value={tipUrl}
                size={148}
                level="M"
                includeMargin={false}
                bgColor={qrBg}
                fgColor={qrFg}
              />
            </div>
            <Button
              type="button"
              variant="editorial"
              size="sm"
              className={`!w-fit shrink-0 justify-center ${settingsUniformH}`}
              icon={<Download size={16} />}
              onClick={downloadQrPng}
            >
              Download PNG
            </Button>
          </div>
        </div>
      </div>

      <div className="kofi-dashboard-card space-y-4 p-5 shadow-none md:p-6">
        <DashboardSectionHeader
          icon={<Bell {...dashboardSectionIconLucideProps} aria-hidden />}
          title="Notifications"
        >
          <p className="text-pretty text-sm font-medium leading-relaxed text-zap-ink-muted">
            Toggle what you want to hear about. Choices are saved on this device; email and push
            will use them once delivery is connected.
          </p>
        </DashboardSectionHeader>
        <ul className="space-y-2">
          {(
            [
              { id: "tips" as const, label: "Notify me when I receive a zap" },
              { id: "weekly" as const, label: "Weekly summary email" },
              { id: "product" as const, label: "Product updates from Zap402" },
            ] satisfies { id: NotifyPrefId; label: string }[]
          ).map((item) => (
            <li
              key={item.id}
              className="flex items-center justify-between gap-4 rounded-2xl border border-[var(--card-border-soft)] bg-zap-bg/20 px-3 py-2.5 dark:bg-zap-bg/10"
            >
              <label
                htmlFor={`settings-notify-${item.id}`}
                className="cursor-pointer text-sm font-medium text-zap-ink"
              >
                {item.label}
              </label>
              <input
                id={`settings-notify-${item.id}`}
                type="checkbox"
                checked={notifyPrefs[item.id]}
                onChange={(e) => setNotifyPref(item.id, e.target.checked)}
                className="h-4 w-4 shrink-0 cursor-pointer rounded border-zap-border bg-zap-surface text-zap-brand focus:ring-2 focus:ring-zap-brand/30 focus:ring-offset-2 focus:ring-offset-zap-bg"
              />
            </li>
          ))}
        </ul>
      </div>

      <div className="kofi-dashboard-card space-y-4 border border-zap-error/35 bg-zap-error-dim/40 p-5 shadow-none md:p-6 dark:bg-zap-error-dim/25">
        <DashboardSectionHeader
          icon={<AlertTriangle {...dashboardSectionIconLucideProps} aria-hidden />}
          title="Danger zone"
          iconVariant="danger"
          dangerTitle
        >
          <p className="text-pretty text-sm font-medium leading-relaxed text-zap-ink">
            Deregistering removes your creator profile from Zap402. There is no on-chain deregister
            call in the scaffold yet — this action will be wired after the contract supports it.
          </p>
        </DashboardSectionHeader>
        <Button
          type="button"
          variant="editorialGhost"
          size="sm"
          className={`${settingsActionBtnClass} ${settingsUniformH} text-zap-error hover:text-zap-error`}
          icon={<Trash2 size={16} className="text-zap-error" aria-hidden />}
          disabled
        >
          Delete my creator account
        </Button>
      </div>
    </div>
  );
};

export default SettingsTab;
